import { ethers } from "ethers";
import React, { useState, useEffect } from "react";

const TokenSwap = () => {
  const [provider, setProvider] = useState(null);
  const [signer, setSigner] = useState(null);
  const [tokenA, setTokenA] = useState("");
  const [tokenB, setTokenB] = useState("");
  const [amountA, setAmountA] = useState(0);
  const [amountB, setAmountB] = useState(0);

  useEffect(() => {
    if (window.ethereum) {
      setProvider(new ethers.providers.Web3Provider(window.ethereum));
      window.ethereum.request({ method: "eth_requestAccounts" }).then((accounts) => {
        setSigner(provider.getSigner(accounts[0]));
      });
    }
  }, []);

  const swapTokens = async () => {
    const erc20A = new ethers.Contract(tokenA, ERC20_ABI, signer);
    await erc20A.approve(DEX_CONTRACT_ADDRESS, ethers.constants.MaxUint256);

    const dexContract = new ethers.Contract(DEX_CONTRACT_ADDRESS, DEX_ABI, signer);
    await dexContract.swapTokens(tokenA, tokenB, amountA);

    setAmountB((await dexContract.getExpectedOutput(tokenA, tokenB, amountA)).toString());
  };

  return (
    <div>
      <input
        type="text"
        placeholder="Token A Address"
        value={tokenA}
        onChange={(e) => setTokenA(e.target.value)}
      />
      <input
        type="number"
        placeholder="Amount A"
        value={amountA}
        onChange={(e) => setAmountA(Number(e.target.value))}
      />
      <button onClick={swapTokens}>Swap</button>
    </div>
  );
};

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) returns (bool)",
];

const DEX_CONTRACT_ADDRESS = "0x..."; // Replace with the actual DEX contract address
const DEX_ABI = [
  "function swapTokens(address tokenA, address tokenB, uint256 amountA) external",
  "function getExpectedOutput(address tokenA, address tokenB, uint256 amountA) external view returns (uint256)",
];

export default TokenSwap;